1	'use strict';
2	// 명령 로직의 단일 소스. CLI(bin/aad.js)와 서버(server/serve.js)가 모두 여기를 호출한다.
3	// 여기 함수들은 콘솔 출력/exit을 하지 않고 "데이터"만 돌려준다 (CLI는 출력용으로 포장, 서버는 JSON으로).
4	
5	const fs = require('fs');
6	const path = require('path');
7	const crypto = require('crypto');
8	const { execFileSync } = require('child_process');
9	const matter = require('gray-matter');
10	
11	const paths = require('./paths');
12	const scanner = require('./scanner');
13	const canonical = require('./canonical');
14	const security = require('./security');
15	const diff = require('./diff');
16	const backup = require('./backup');
17	const transformInstr = require('./transform/instructions');
18	const transformAgent = require('./transform/agent');
19	const transformSkill = require('./transform/skill');
20	const telemetry = require('./telemetry');
21	const maintenance = require('./maintenance');
22	const synclog = require('./synclog');
23	const store = require('./store');
24	const registry = require('./registry');
25	const category = require('./category');
26	const search = require('./search');
27	const playground = require('./playground');
28	const projects = require('./projects');
29	
30	const CANON_ID = 'instr-global'; // 슬라이스: 글로벌 지시문 1개
31	
32	// PI 게이트에 걸렸음을 알리는 전용 에러 (호출자가 사용자 확인을 받게 함)
33	class PiGateError extends Error {
34	  constructor(detected, maskedLines) {
35	    super('PI_GATE');
36	    this.name = 'PiGateError';
37	    this.detected = detected;
38	    this.maskedLines = maskedLines;
39	  }
40	}
41	
42	// canonical 저장소에 변경 커밋 (로컬 전용). 미초기화/변경없음이면 조용히 넘어감.
43	// 주의: canonical 폴더 "자체"가 git 저장소일 때만 커밋한다. 자체 저장소가 아니면
44	// rev-parse가 상위(프로젝트) 저장소에서 성공해 add -A가 저장소 전체를 커밋해버리므로
45	// toplevel == canonicalRoot 을 확인하고, add도 canonical 하위로만 한정한다.
46	function gitCommit(message) {
47	  const cwd = paths.canonicalRoot();
48	  let top;
49	  try {
50	    top = execFileSync('git', ['rev-parse', '--show-toplevel'], { cwd, encoding: 'utf8' }).trim();
51	  } catch {
52	    return;
53	  }
54	  try {
55	    if (path.resolve(fs.realpathSync(top)) !== path.resolve(fs.realpathSync(cwd))) return;
56	  } catch {
57	    return;
58	  }
59	  try {
60	    execFileSync('git', ['add', '-A', '--', '.'], { cwd, stdio: 'ignore' });
61	    execFileSync('git', ['commit', '-m', message], { cwd, stdio: 'ignore' });
62	  } catch {
63	    /* 변경 없음 등 무시 */
64	  }
65	}
66	
67	// ================= 프로젝트 레지스트리 (T2) =================
68	// 로직은 cli/projects.js 단일 소스 — 여기는 위임 래퍼만 둔다.
69	
70	// 등록된 프로젝트 목록.
71	function projectsList() {
72	  return { projects: projects.list() };
73	}
74	
75	// 디스크 스캔(존재/이름만) — 후보 반환만 하고 자동 등록하지 않는다.
76	// root 미지정 시 모드별 기본 루트(더미=fixtures/projects, 실제=홈).
77	function projectsScan({ root } = {}) {
78	  const scanRoot = root || paths.projectScanDefaultRoot();
79	  const known = new Set(projects.list().map((p) => p.root));
80	  const candidates = projects
81	    .scan(scanRoot)
82	    .map((c) => ({ ...c, registered: known.has(c.root) }));
83	  return { root: scanRoot, candidates };
84	}
85	
86	// scan 결과(후보)를 레지스트리에 병합 — 사용자가 명시적으로 채택할 때만.
87	function projectsAdopt({ candidates } = {}) {
88	  return projects.adoptScan(candidates || []);
89	}
90	
91	function projectsAdd({ root }) {
92	  if (!root) throw new Error('root 경로가 필요합니다');
93	  return projects.add(root);
94	}
95	
96	function projectsRemove({ root }) {
97	  if (!root) throw new Error('root 경로가 필요합니다');
98	  return projects.remove(root);
99	}
100	
101	// 자동 발견 (UX-E1): 레지스트리(projects.json)가 비어 있을 때만 1회 스캔 후 자동 등록.
102	//  - 비어 있지 않으면 아무것도 하지 않는다("최초 1회만 스캔" 결정 유지, D27-③).
103	//  - 트리거는 사용자가 매트릭스 화면을 여는 것(자동 폴링 아님, D14 정합).
104	//  - 반환: { scanned:boolean, adopted:number }.
105	function projectsEnsureScanned() {
106	  if (projects.list().length > 0) return { scanned: false, adopted: 0 };
107	  const candidates = projects.scan(paths.projectScanDefaultRoot());
108	  const r = projects.adoptScan(candidates);
109	  return { scanned: true, adopted: r.adopted };
110	}
111	
112	// (보안 가드) 등록된 프로젝트만 pull 소스로 허용 — 임의 경로 읽기를 코드로 차단.
113	function requireRegisteredProject(root) {
114	  const abs = path.resolve(root);
115	  const found = projects.list().find((p) => p.root === abs);
116	  if (!found) throw new Error('등록되지 않은 프로젝트입니다 (먼저 aad projects add --root <path>): ' + abs);
117	  return abs;
118	}
119	
120	// 하이브리드: 존재만 (내용 안 읽음) + canonical 존재 여부
121	function overview() {
122	  const items = scanner.discoverInstructions().map((it) => ({
123	    id: it.id,
124	    type: it.type,
125	    scope: it.scope,
126	    tool: it.tool,
127	    name: it.name,
128	    exists: it.exists,
129	  }));
130	  // T2: 등록 프로젝트의 지시문은 "존재 여부만" 별도 필드로 노출.
131	  // items에 합치지 않는 이유: 지시문 트랙은 단일 canonical(instr-global) 구조라
132	  // 기존 소비자(status drift 계산·대시보드 카운트)가 items=글로벌 전제를 갖는다.
133	  // 프로젝트 지시문의 pull/push는 이번 범위 밖 — 표시 전용.
134	  const projectItems = scanner.discoverProjectInstructions().map((it) => ({
135	    id: it.id,
136	    type: it.type,
137	    scope: it.scope,
138	    projectRoot: it.projectRoot,
139	    tool: it.tool,
140	    name: it.name,
141	    exists: it.exists,
142	  }));
143	  const canon = canonical.read(CANON_ID);
144	  return {
145	    canonId: CANON_ID,
146	    canonicalExists: !!canon,
147	    source: canon ? canon.meta.source_tool : null,
148	    items,
149	    projectItems,
150	  };
151	}
152	
153	// 클릭 시: 특정 도구 배포본과 canonical의 drift (내용 읽기 — 사용자 동작)
154	function diffFor(tool) {
155	  if (!paths.TOOLS.includes(tool)) throw new Error('알 수 없는 도구: ' + tool);
156	  const canon = canonical.read(CANON_ID);
157	  if (!canon) return { canonicalExists: false };
158	  const target = paths.instructionPath(tool);
159	  const deployed = fs.existsSync(target) ? fs.readFileSync(target, 'utf8') : '';
160	  const d = diff.lineDiff(canon.body, deployed);
161	  return {
162	    canonicalExists: true,
163	    tool,
164	    exists: fs.existsSync(target),
165	    targetPath: target,
166	    diff: d,
167	    hasChanges: diff.hasChanges(d),
168	  };
169	}
170	
171	// import: 도구 지시문 → canonical. PI 감지 시 piAck 없으면 PiGateError를 던진다.
172	function pull({ from, piAck }) {
173	  if (!paths.TOOLS.includes(from)) throw new Error('알 수 없는 도구: ' + from);
174	  const item = scanner.discoverInstructions().find((i) => i.tool === from);
175	  if (!item.exists) throw new Error(`${from}의 지시문 파일이 없습니다: ${item.path}`);
176	
177	  let { text, pi } = scanner.readItemContent(item);
178	  if (pi.length > 0) {
179	    if (!piAck) throw new PiGateError(pi, security.maskedSensitiveLines(text));
180	    if (piAck === 'exclude') return { imported: false, reason: 'excluded' };
181	    if (piAck === 'mask') text = security.mask(text);
182	    // 'proceed' → 그대로
183	  }
184	  const meta = canonical.write(CANON_ID, text, { sourceTool: from });
185	  gitCommit(`pull: ${from} → canonical (${CANON_ID})`);
186	  return { imported: true, meta, piHandled: pi.length ? piAck : null };
187	}
188	
189	// sync: canonical → 도구. apply=false면 미리보기(diff)만, true면 백업 후 쓰기.
190	function push({ to, apply }) {
191	  if (!paths.TOOLS.includes(to)) throw new Error('알 수 없는 도구: ' + to);
192	  const canon = canonical.read(CANON_ID);
193	  if (!canon) throw new Error('canonical이 비어 있습니다. 먼저 pull 하세요.');
194	
195	  const rendered = transformInstr.render(canon.body, to);
196	  const deployed = fs.existsSync(rendered.targetPath)
197	    ? fs.readFileSync(rendered.targetPath, 'utf8')
198	    : '';
199	  const d = diff.lineDiff(deployed, rendered.body);
200	
201	  if (!apply) {
202	    return {
203	      applied: false,
204	      to,
205	      targetPath: rendered.targetPath,
206	      diff: d,
207	      hasChanges: diff.hasChanges(d),
208	      losses: rendered.losses,
209	    };
210	  }
211	  const backupPath = backup.backupFile(rendered.targetPath, to, { kind: 'instruction', item: CANON_ID });
212	  fs.mkdirSync(path.dirname(rendered.targetPath), { recursive: true });
213	  fs.writeFileSync(rendered.targetPath, rendered.body);
214	  synclog.recordPush(to);
215	  return { applied: true, to, targetPath: rendered.targetPath, backupPath, losses: rendered.losses };
216	}
217	
218	// ================= agent 트랙 =================
219	
220	// 개요: canonical agent 목록 + 도구별 발견(존재) + 비표준 파일
221	function agentOverview() {
222	  const disc = scanner.discoverAgents();
223	  return {
224	    canonicalAgents: canonical.listAgents().map((a) => ({
225	      id: a.id,
226	      name: a.name,
227	      tools: a.tools || [],
228	      source_tool: a.source_tool,
229	      tags: a.tags || [],
230	      // T2: 프로젝트에서 pull한 항목 표시 (글로벌 항목은 필드 없음 → JSON에서 생략됨)
231	      scope: a.scope,
232	      project_root: a.project_root,
233	    })),
234	    toolAgents: disc.agents, // {tool, name, ...}
235	    nonStandard: disc.nonStandard,
236	  };
237	}
238	
239	// import: 도구의 agent 파일 → canonical 중립 스키마. PI 게이트 적용.
240	// T2: projectRoot가 있으면 "등록된 프로젝트"의 agent 폴더에서 읽는다 (미등록 경로는 거부).
241	function agentPull({ from, name, piAck, projectRoot }) {
242	  if (!paths.TOOLS.includes(from)) throw new Error('알 수 없는 도구: ' + from);
243	  const projRoot = projectRoot ? requireRegisteredProject(projectRoot) : null;
244	  const filePath = projRoot
245	    ? path.join(paths.projectAgentDir(projRoot, from), name + paths.agentExt(from))
246	    : paths.agentPath(from, name);
247	  if (!fs.existsSync(filePath)) throw new Error(`agent 파일이 없습니다: ${filePath}`);
248	
249	  let { text, pi } = scanner.readItemContent({ path: filePath });
250	  if (pi.length > 0) {
251	    if (!piAck) throw new PiGateError(pi, security.maskedSensitiveLines(text));
252	    if (piAck === 'exclude') return { imported: false, reason: 'excluded' };
253	    if (piAck === 'mask') text = security.mask(text);
254	  }
255	  const neutral = transformAgent.parse(text, from, name);
256	  // 프로젝트 출처 표기 — writeAgent는 중립 스키마를 spread로 보존하므로 여기서 필드만 더한다.
257	  if (projRoot) {
258	    neutral.scope = 'project';
259	    neutral.project_root = projRoot;
260	  } else {
261	    neutral.scope = 'global';
262	  }
263	  const record = canonical.writeAgent(neutral);
264	  gitCommit(`pull agent: ${projRoot ? projRoot + ':' : ''}${from}/${name} → canonical (${record.id})`);
265	  return { imported: true, agent: record, piHandled: pi.length ? piAck : null };
266	}
267	
268	// 미리보기: canonical agent → 특정 도구 렌더 결과(diff + 손실)
269	function agentDiff(id, to) {
270	  const neutral = canonical.readAgent(id);
271	  if (!neutral) return { canonicalExists: false };
272	  const rendered = transformAgent.render(neutral, to);
273	  const target = paths.agentPath(to, neutral.name);
274	  const deployed = fs.existsSync(target) ? fs.readFileSync(target, 'utf8') : '';
275	  const d = diff.lineDiff(deployed, rendered.content);
276	  return {
277	    canonicalExists: true,
278	    to,
279	    targetPath: target,
280	    diff: d,
281	    hasChanges: diff.hasChanges(d),
282	    losses: rendered.losses,
283	  };
284	}
285	
286	// sync: canonical agent → 도구. apply=false면 미리보기, true면 백업 후 쓰기.
287	function agentPush({ id, to, apply }) {
288	  if (!paths.TOOLS.includes(to)) throw new Error('알 수 없는 도구: ' + to);
289	  const neutral = canonical.readAgent(id);
290	  if (!neutral) throw new Error('canonical에 해당 agent가 없습니다: ' + id);
291	  const rendered = transformAgent.render(neutral, to);
292	  const target = paths.agentPath(to, neutral.name);
293	  const deployed = fs.existsSync(target) ? fs.readFileSync(target, 'utf8') : '';
294	  const d = diff.lineDiff(deployed, rendered.content);
295	
296	  if (!apply) {
297	    return { applied: false, to, targetPath: target, diff: d, hasChanges: diff.hasChanges(d), losses: rendered.losses };
298	  }
299	  const backupPath = backup.backupFile(target, to, { kind: 'agent', item: neutral.name });
300	  fs.mkdirSync(path.dirname(target), { recursive: true });
301	  fs.writeFileSync(target, rendered.content);
302	  synclog.recordPush(to);
303	  return { applied: true, to, targetPath: target, backupPath, losses: rendered.losses };
304	}
305	
306	// ================= skill 트랙 =================
307	
308	// 개요: canonical skill 목록 + 도구별 발견(존재). 비공식 소스는 official:false로 표시(D11).
309	function skillOverview() {
310	  const discovered = scanner.discoverSkills();
311	  return {
312	    canonicalSkills: canonical.listSkills().map((s) => ({
313	      id: s.id,
314	      name: s.name,
315	      source_tool: s.source_tool,
316	      official: s.official,
317	      tags: s.tags || [],
318	      // T2: 프로젝트에서 pull한 항목 표시 (글로벌 항목은 필드 없음 → JSON에서 생략됨)
319	      scope: s.scope,
320	      project_root: s.project_root,
321	    })),
322	    toolSkills: discovered, // {name, tool, source_id, official, shared, plugin, path}
323	    // 비공식 위치의 skill은 별도로 모아 사용자에게 알릴 수 있게 한다
324	    unofficial: discovered.filter((s) => s.official === false),
325	  };
326	}
327	
328	// import: 도구의 skill(SKILL.md) → canonical. PI 게이트 적용. name으로 첫 매칭 소스를 쓴다.
329	// T2: projectRoot가 있으면 "등록된 프로젝트"의 소스로 좁힌다 (글로벌이 목록 앞이라 기본 동작 불변).
330	function skillPull({ name, source_id, piAck, projectRoot }) {
331	  let matches = scanner.discoverSkills().filter((s) => s.name === name);
332	  if (!matches.length) throw new Error(`skill을 찾을 수 없습니다: ${name}`);
333	  if (projectRoot) {
334	    const projRoot = requireRegisteredProject(projectRoot);
335	    matches = matches.filter((s) => s.projectRoot === projRoot);
336	    if (!matches.length) throw new Error(`해당 프로젝트에 skill이 없습니다: ${name} (${projRoot})`);
337	  }
338	  // source_id가 주어지면 그 소스, 아니면 첫 매칭
339	  const item = source_id ? matches.find((s) => s.source_id === source_id) : matches[0];
340	  if (!item) throw new Error(`해당 소스에 skill이 없습니다: ${name} (${source_id})`);
341	
342	  let { text, pi } = scanner.readItemContent({ path: item.path });
343	  if (pi.length > 0) {
344	    if (!piAck) throw new PiGateError(pi, security.maskedSensitiveLines(text));
345	    if (piAck === 'exclude') return { imported: false, reason: 'excluded' };
346	    if (piAck === 'mask') text = security.mask(text);
347	  }
348	  const meta = canonical.writeSkill(name, text, {
349	    source_id: item.source_id,
350	    source_tool: item.tool,
351	    official: item.official,
352	    // 프로젝트 출처 표기 — 글로벌 pull은 scope:'global' + project_root 제거(null)로 정리.
353	    scope: item.scope === 'project' ? 'project' : 'global',
354	    project_root: item.scope === 'project' ? item.projectRoot : null,
355	  });
356	  gitCommit(`pull skill: ${item.source_id}/${name} → canonical`);
357	  return { imported: true, skill: meta, unofficialSource: item.official === false, piHandled: pi.length ? piAck : null };
358	}
359	
360	// 미리보기: canonical skill → 특정 도구로 복사할 결과(diff)
361	function skillDiff(name, to) {
362	  const canon = canonical.readSkill(name);
363	  if (!canon) return { canonicalExists: false };
364	  const rendered = transformSkill.render(canon.body, name, to);
365	  const deployed = fs.existsSync(rendered.targetPath) ? fs.readFileSync(rendered.targetPath, 'utf8') : '';
366	  const d = diff.lineDiff(deployed, rendered.content);
367	  return {
368	    canonicalExists: true,
369	    to,
370	    targetPath: rendered.targetPath,
371	    diff: d,
372	    hasChanges: diff.hasChanges(d),
373	    losses: rendered.losses,
374	  };
375	}
376	
377	// sync: canonical skill → 도구. apply=false면 미리보기, true면 백업 후 쓰기.
378	function skillPush({ name, to, apply }) {
379	  const canon = canonical.readSkill(name);
380	  if (!canon) throw new Error('canonical에 해당 skill이 없습니다: ' + name);
381	  const rendered = transformSkill.render(canon.body, name, to);
382	  const deployed = fs.existsSync(rendered.targetPath) ? fs.readFileSync(rendered.targetPath, 'utf8') : '';
383	  const d = diff.lineDiff(deployed, rendered.content);
384	  if (!apply) {
385	    return { applied: false, to, targetPath: rendered.targetPath, diff: d, hasChanges: diff.hasChanges(d), losses: rendered.losses };
386	  }
387	  const backupPath = backup.backupFile(rendered.targetPath, to, { kind: 'skill', item: name });
388	  fs.mkdirSync(path.dirname(rendered.targetPath), { recursive: true });
389	  fs.writeFileSync(rendered.targetPath, rendered.content);
390	  synclog.recordPush(to);
391	  return { applied: true, to, targetPath: rendered.targetPath, backupPath, losses: rendered.losses };
392	}
393	
394	// ================= 한 번에 동기화(Sync) — UX-A =================
395	// 사용자가 "미등록 소스"에서 [Sync]를 명시적으로 누른 항목이므로 각 도구 사본의
396	// 내용을 읽어 비교해도 된다(D9: 클릭 시 읽기). 실제 쓰기는 syncApply만 하고,
397	// 그 쓰기는 전부 기존 pull/push 함수 경유 → PI 게이트·백업·synclog·gitCommit 자동 상속.
398	// 새 쓰기 경로는 만들지 않는다.
399	
400	function contentHash(text) {
401	  return crypto.createHash('sha256').update(text == null ? '' : text, 'utf8').digest('hex').slice(0, 12);
402	}
403	
404	// agent "내용 동일" 판정 = 비교 대상 필드만 정규화한 JSON 해시.
405	// syncPlan(agentSyncPlan)과 syncMatrix가 공유한다(단일 규칙).
406	function agentNeutralKey(n) {
407	  return contentHash(
408	    JSON.stringify({
409	      name: n.name || '',
410	      description: n.description || '',
411	      system_prompt: n.system_prompt || '',
412	      model: n.model || null,
413	      tools: [...(n.tools || [])].sort(),
414	    })
415	  );
416	}
