418	// skill 동기화의 "도구 슬롯" = push 대상과 대칭인 3개 위치.
419	//  - claude → ~/.claude/skills(claude-user)
420	//  - codex  → .agents/skills(shared-agents, discoverSkills에선 tool='shared')
421	//  - gemini → ~/.gemini/skills(gemini-user)
422	// discoverSkills가 돌려준 항목 중 위 공식 소스만 도구 슬롯에 매핑한다.
423	// (플러그인/비공식/프로젝트 소스는 baseCandidate가 아니라 notes로만 알린다.)
424	const SKILL_TOOL_SOURCE = { claude: 'claude-user', codex: 'shared-agents', gemini: 'gemini-user' };
425	
426	// (1) 동기화 계획 — 읽기 전용(디스크 쓰기 0). kind: 'skill'|'agent'.
427	function syncPlan({ kind, name }) {
428	  if (kind === 'skill') return skillSyncPlan(name);
429	  if (kind === 'agent') return agentSyncPlan(name);
430	  throw new Error('알 수 없는 kind: ' + kind + " ('skill'|'agent')");
431	}
432	
433	// skill: 도구별 SKILL.md 내용 해시로 그룹핑. canonical 동명 항목도 참고 정보로 포함.
434	function skillSyncPlan(name) {
435	  if (!name) throw new Error('name이 필요합니다');
436	  const discovered = scanner.discoverSkills().filter((s) => s.name === name);
437	  const canon = canonical.readSkill(name);
438	  const canonicalExists = !!canon;
439	  const canonicalHash = canonicalExists ? contentHash(canon.body) : null;
440	
441	  // 내용 → 그룹 번호(1부터). canonical 내용도 같은 사전에 넣어 "같은 그룹"이면 도구=canonical.
442	  const groupOf = new Map();
443	  let nextGroup = 0;
444	  function assignGroup(h) {
445	    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
446	    return groupOf.get(h);
447	  }
448	  if (canonicalExists) assignGroup(canonicalHash);
449	
450	  const tools = paths.TOOLS.map((tool) => {
451	    const sourceId = SKILL_TOOL_SOURCE[tool];
452	    // 이 도구 슬롯(공식 push 대상)에 실제로 발견된 skill
453	    const official = discovered.find((s) => s.source_id === sourceId && s.scope !== 'project');
454	    const notes = [];
455	    // 같은 이름이 비공식/플러그인/프로젝트 위치에도 있으면 특이사항으로 알린다.
456	    for (const s of discovered) {
457	      if (s.source_id === sourceId && s.scope !== 'project') continue;
458	      if (s.official === false) notes.push(`비공식 위치에도 존재: ${s.path}`);
459	      else if (s.plugin) notes.push(`플러그인 위치에도 존재: ${s.path}`);
460	      else if (s.scope === 'project') notes.push(`프로젝트 스코프에도 존재(@${s.projectRoot}): ${s.path}`);
461	      else if (SKILL_TOOL_SOURCE[tool] !== s.source_id) {
462	        // 다른 도구 슬롯의 것 — 여기서는 건너뜀(각 도구 항목에서 다룸)
463	      }
464	    }
465	    if (!official) {
466	      return { tool, exists: false, sourceId, official: true, group: null, notes };
467	    }
468	    const { text } = scanner.readItemContent({ path: official.path });
469	    const group = assignGroup(contentHash(text));
470	    return {
471	      tool,
472	      exists: true,
473	      sourceId: official.source_id,
474	      official: official.official !== false,
475	      scope: official.scope || 'global',
476	      group,
477	      notes,
478	    };
479	  });
480	
481	  const baseCandidates = tools.filter((t) => t.exists).map((t) => t.tool);
482	  return {
483	    kind: 'skill',
484	    name,
485	    canonicalExists,
486	    canonicalGroup: canonicalExists ? groupOf.get(canonicalHash) : null,
487	    tools,
488	    groups: groupOf.size,
489	    baseCandidates,
490	    // 스킬은 도구 간 변환 손실이 없다(SKILL.md 복사) → perBaseLosses는 빈 요약.
491	    perBaseLosses: Object.fromEntries(baseCandidates.map((t) => [t, {}])),
492	  };
493	}
494	
495	// agent: 도구별 파일 파싱(transform 재사용) 후 중립 스키마 비교 + 기준별 변환 손실.
496	function agentSyncPlan(name) {
497	  if (!name) throw new Error('name이 필요합니다');
498	  const id = 'agent-' + name;
499	  const disc = scanner.discoverAgents().agents.filter((a) => a.name === name && a.scope !== 'project');
500	  const canonNeutral = canonical.readAgent(id);
501	  const canonicalExists = !!canonNeutral;
502	
503	  // 중립 스키마의 "내용 동일" 판정은 agentNeutralKey(모듈 공유)로 위임.
504	  const neutralKey = agentNeutralKey;
505	  const groupOf = new Map();
506	  let nextGroup = 0;
507	  function assignGroup(h) {
508	    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
509	    return groupOf.get(h);
510	  }
511	  if (canonicalExists) assignGroup(neutralKey(canonNeutral));
512	
513	  // 각 도구별로 파싱한 중립 스키마를 담아둔다(perBaseLosses 계산에 재사용).
514	  const parsedByTool = {};
515	  const tools = paths.TOOLS.map((tool) => {
516	    const found = disc.find((a) => a.tool === tool);
517	    const notes = [];
518	    if (!found) {
519	      // Codex는 에이전트별 tools 필드가 없다는 구조적 특이사항을 미리 알린다.
520	      if (tool === 'codex') notes.push('codex는 에이전트별 tools 필드가 없음 → tools는 codex로 내보낼 때 손실');
521	      return { tool, exists: false, group: null, notes };
522	    }
523	    const { text } = scanner.readItemContent({ path: found.path });
524	    const neutral = transformAgent.parse(text, tool, name);
525	    parsedByTool[tool] = neutral;
526	    const group = assignGroup(neutralKey(neutral));
527	    if (tool === 'codex') notes.push('codex 파일은 tools 필드가 없어 tools 정보가 없음(중립 스키마 tools=[])');
528	    if (neutral.source_notes) notes.push(neutral.source_notes);
529	    return { tool, exists: true, scope: found.scope || 'global', group, notes };
530	  });
531	
532	  const baseCandidates = tools.filter((t) => t.exists).map((t) => t.tool);
533	  // 각 후보를 기준으로 삼았을 때, 다른 도구로 render 시 생기는 손실 요약.
534	  const perBaseLosses = {};
535	  for (const base of baseCandidates) {
536	    const neutral = parsedByTool[base];
537	    const losses = {};
538	    for (const target of paths.TOOLS) {
539	      if (target === base) continue;
540	      losses[target] = transformAgent.render(neutral, target).losses;
541	    }
542	    perBaseLosses[base] = losses;
543	  }
544	
545	  return {
546	    kind: 'agent',
547	    name,
548	    canonicalExists,
549	    canonicalGroup: canonicalExists ? groupOf.get(neutralKey(canonNeutral)) : null,
550	    tools,
551	    groups: groupOf.size,
552	    baseCandidates,
553	    perBaseLosses,
554	  };
555	}
