557	// (2) 동기화 실행 — pull(기준→canonical) + push(나머지 도구, 내용 다르거나 없으면).
558	//  모든 쓰기는 기존 skillPull/agentPull/skillPush/agentPush 경유.
559	//  PI 감지 시 pull이 PiGateError를 던지며, 여기서 잡지 않고 그대로 전파(서버 409).
560	function syncApply({ kind, name, baseTool, sourceId, piAck }) {
561	  if (kind !== 'skill' && kind !== 'agent') throw new Error("알 수 없는 kind: " + kind + " ('skill'|'agent')");
562	  if (!name) throw new Error('name이 필요합니다');
563	  if (!paths.TOOLS.includes(baseTool)) throw new Error('기준 도구가 올바르지 않습니다(baseTool): ' + baseTool);
564	
565	  const plan = syncPlan({ kind, name });
566	  const baseSlot = plan.tools.find((t) => t.tool === baseTool);
567	  if (!baseSlot || !baseSlot.exists) {
568	    throw new Error(`기준 도구(${baseTool})에 ${kind} "${name}"가 없습니다. baseCandidates: [${plan.baseCandidates.join(', ')}]`);
569	  }
570	
571	  // 1) pull: 기준 도구 → canonical (기존 함수 재사용 — PI 게이트/gitCommit 상속)
572	  let pulled;
573	  if (kind === 'skill') {
574	    const r = skillPull({ name, source_id: sourceId || SKILL_TOOL_SOURCE[baseTool], piAck });
575	    if (!r.imported) return { pulled: { from: baseTool, imported: false, reason: r.reason }, results: [] };
576	    pulled = { from: baseTool, kind: 'skill', name, source_tool: r.skill.source_tool, unofficialSource: r.unofficialSource, piHandled: r.piHandled };
577	  } else {
578	    const r = agentPull({ from: baseTool, name, piAck });
579	    if (!r.imported) return { pulled: { from: baseTool, imported: false, reason: r.reason }, results: [] };
580	    pulled = { from: baseTool, kind: 'agent', id: r.agent.id, source_tool: r.agent.source_tool, piHandled: r.piHandled };
581	  }
582	
583	  // pull 이후의 canonical 내용으로 나머지 도구와 비교(기준 자신은 skip).
584	  const results = [];
585	  for (const tool of paths.TOOLS) {
586	    if (tool === baseTool) continue;
587	    try {
588	      const preview = kind === 'skill'
589	        ? skillPush({ name, to: tool, apply: false })
590	        : agentPush({ id: 'agent-' + name, to: tool, apply: false });
591	      if (!preview.hasChanges) {
592	        // canonical과 내용 동일(대상이 이미 존재하고 같음) → skip
593	        results.push({ tool, action: 'skipped_same', targetPath: preview.targetPath, losses: preview.losses });
594	        continue;
595	      }
596	      const applied = kind === 'skill'
597	        ? skillPush({ name, to: tool, apply: true })
598	        : agentPush({ id: 'agent-' + name, to: tool, apply: true });
599	      results.push({ tool, action: 'pushed', targetPath: applied.targetPath, backup: applied.backupPath, losses: applied.losses });
600	    } catch (e) {
601	      // 부분 실패: 중단하지 말고 도구별 결과로 기록.
602	      results.push({ tool, action: 'error', error: e.message });
603	    }
604	  }
605	  return { pulled, results };
606	}
