608	// ================= 동기화 매트릭스 (UX-E1) =================
609	// D27: 화면의 주인공 = "홈(~)과 각 프로젝트의 스킬·에이전트가 서로 동기화되어 있는가".
610	// 행 = (scope, name). scope = 'global'(전역 ~) 또는 등록 프로젝트 root.
611	// 각 행은 3개 도구(claude/codex/gemini) 슬롯의 존재/내용해시그룹 + 동기화 상태를 담는다.
612	//
613	// 읽기 전용(디스크 쓰기 0). 로컬 파일이므로 표 로드 시 그대로 읽어 해시 계산(캐시 불필요, D27-④).
614	// 파일 읽기 실패는 "행 단위 error"로 우아하게 표면화하고 전체는 계속 계산한다(D26-② 우아한 실패).
615	
616	// scope 라벨: 전역은 '전역(~)', 프로젝트는 '폴더명 (전체경로)'.
617	function scopeLabelFor(scope) {
618	  if (scope === 'global') return '전역(~)';
619	  return path.basename(scope) + ' (' + scope + ')';
620	}
621	
622	// canonical 메타의 동명 항목 태그를 우선, 없으면 파일 frontmatter의 tags(있을 때만).
623	function skillTagsFor(name, fallbackText) {
624	  const canon = canonical.readSkill(name);
625	  if (canon && Array.isArray(canon.meta.tags) && canon.meta.tags.length) return canon.meta.tags;
626	  if (fallbackText != null) {
627	    try {
628	      const fm = matter(fallbackText).data || {};
629	      if (Array.isArray(fm.tags) && fm.tags.length) return fm.tags;
630	    } catch {
631	      /* frontmatter 파싱 실패 — 태그 없음으로 취급 */
632	    }
633	  }
634	  return [];
635	}
636	function agentTagsFor(name, fallbackNeutral) {
637	  const canon = canonical.readAgent('agent-' + name);
638	  if (canon && Array.isArray(canon.tags) && canon.tags.length) return canon.tags;
639	  if (fallbackNeutral && Array.isArray(fallbackNeutral.tags) && fallbackNeutral.tags.length) {
640	    return fallbackNeutral.tags;
641	  }
642	  return [];
643	}
644	
645	// 세 도구 슬롯의 group(내용 그룹 번호)으로 동기화 상태를 판정한다.
646	//  - synced : 3도구 모두 존재 + 같은 그룹
647	//  - drift  : 존재하는 것 중 서로 다른 그룹이 섞임(내용 다름)
648	//  - partial: 일부 도구에만 있지만 있는 것끼리는 동일
649	//  - single : 1곳만 존재
650	function syncStateOf(toolSlots) {
651	  const present = paths.TOOLS.map((t) => toolSlots[t]).filter((s) => s && s.exists && s.group != null);
652	  if (present.length === 0) return 'single'; // (이론상 매트릭스에 안 올라오지만 방어적으로)
653	  if (present.length === 1) return 'single';
654	  const groups = new Set(present.map((s) => s.group));
655	  if (groups.size > 1) return 'drift';
656	  // 그룹 1개(있는 것끼리 동일) → 3도구 모두면 synced, 일부면 partial
657	  return present.length === paths.TOOLS.length ? 'synced' : 'partial';
658	}
