660	// ── skill 매트릭스 ──
661	// scope 슬롯: global은 SKILL_TOOL_SOURCE(공식 push 대상)와 대칭.
662	//             project는 projectSkillSources(claude/shared/gemini)와 대칭.
663	// codex 열은 shared(.agents/skills) 소스를 매핑한다(push 대칭과 동일, syncPlan과 정합).
664	function skillMatrix() {
665	  const discovered = scanner.discoverSkills();
666	
667	  // 행 키 = scope|name. scope = 'global' | projectRoot.
668	  // 각 (scope,name)에 대해 도구 슬롯을 채운다.
669	  //  - global 슬롯 매핑: claude→claude-user, codex→shared-agents, gemini→gemini-user
670	  //  - project 슬롯 매핑: claude→claude-project, codex→shared-project, gemini→gemini-project
671	  const GLOBAL_SLOT = { claude: 'claude-user', codex: 'shared-agents', gemini: 'gemini-user' };
672	  const PROJECT_SLOT = { claude: 'claude-project', codex: 'shared-project', gemini: 'gemini-project' };
673	
674	  // rows[rowKey] = { scope, name, slotItem:{tool->discovered item} }
675	  const rows = new Map();
676	  function rowFor(scope, name) {
677	    const key = scope + '�' + name;
678	    if (!rows.has(key)) rows.set(key, { scope, name, slots: {} });
679	    return rows.get(key);
680	  }
681	  for (const s of discovered) {
682	    const scope = s.scope === 'project' ? s.projectRoot : 'global';
683	    const slotMap = scope === 'global' ? GLOBAL_SLOT : PROJECT_SLOT;
684	    // 이 항목이 어느 도구 열에 속하는지 = source_id로 역매핑.
685	    const tool = paths.TOOLS.find((t) => slotMap[t] === s.source_id);
686	    if (!tool) continue; // 플러그인/비공식/codex-native 등 도구 열 밖 소스는 매트릭스 슬롯에 넣지 않음
687	    const row = rowFor(scope, s.name);
688	    if (!row.slots[tool]) row.slots[tool] = s; // 첫 매칭만(중복 방지)
689	  }
690	
691	  return [...rows.values()].map((row) => buildSkillRow(row));
692	}
693	
694	function buildSkillRow(row) {
695	  const { scope, name } = row;
696	  const errors = [];
697	  // 행별 내용 해시 그룹(존재 사본만). canonical도 참고용으로 같은 사전에 넣는다.
698	  const groupOf = new Map();
699	  let nextGroup = 0;
700	  const assign = (h) => {
701	    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
702	    return groupOf.get(h);
703	  };
704	  const canon = canonical.readSkill(name);
705	  const canonicalExists = !!canon;
706	  if (canonicalExists) assign(contentHash(canon.body));
707	
708	  let anyText = null;
709	  const tools = {};
710	  for (const tool of paths.TOOLS) {
711	    const item = row.slots[tool];
712	    if (!item) {
713	      tools[tool] = { exists: false, group: null };
714	      continue;
715	    }
716	    try {
717	      const { text } = scanner.readItemContent({ path: item.path });
718	      if (anyText == null) anyText = text;
719	      tools[tool] = { exists: true, group: assign(contentHash(text)) };
720	    } catch (e) {
721	      // 우아한 실패(D26): 이 도구 슬롯만 error, 나머지는 계속.
722	      tools[tool] = { exists: false, group: null, error: e.message };
723	      errors.push(tool + ': ' + e.message);
724	    }
725	  }
726	  return {
727	    scope,
728	    scopeLabel: scopeLabelFor(scope),
729	    name,
730	    tags: skillTagsFor(name, anyText),
731	    tools,
732	    groups: groupOf.size,
733	    syncState: syncStateOf(tools),
734	    canonicalExists,
735	    canonicalGroup: canonicalExists ? groupOf.get(contentHash(canon.body)) : null,
736	    ...(errors.length ? { error: errors.join(' | ') } : {}),
737	  };
738	}
739	
740	// ── agent 매트릭스 ──
741	// 도구별 파일을 파싱(transformAgent.parse)해 중립 스키마로 정규화 후 비교(syncPlan과 동일 규칙).
742	function agentMatrix() {
743	  const disc = scanner.discoverAgents().agents;
744	  // 행 키 = scope|name.
745	  const rows = new Map();
746	  function rowFor(scope, name) {
747	    const key = scope + '�' + name;
748	    if (!rows.has(key)) rows.set(key, { scope, name, slots: {} });
749	    return rows.get(key);
750	  }
751	  for (const a of disc) {
752	    const scope = a.scope === 'project' ? a.projectRoot : 'global';
753	    const row = rowFor(scope, a.name);
754	    if (!row.slots[a.tool]) row.slots[a.tool] = a; // 도구당 첫 파일
755	  }
756	  return [...rows.values()].map((row) => buildAgentRow(row));
757	}
758	
759	function buildAgentRow(row) {
760	  const { scope, name } = row;
761	  const errors = [];
762	  const groupOf = new Map();
763	  let nextGroup = 0;
764	  const assign = (h) => {
765	    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
766	    return groupOf.get(h);
767	  };
768	  const canonNeutral = canonical.readAgent('agent-' + name);
769	  const canonicalExists = !!canonNeutral;
770	  if (canonicalExists) assign(agentNeutralKey(canonNeutral));
771	
772	  let firstNeutral = null;
773	  const tools = {};
774	  for (const tool of paths.TOOLS) {
775	    const item = row.slots[tool];
776	    if (!item) {
777	      tools[tool] = { exists: false, group: null };
778	      continue;
779	    }
780	    try {
781	      const { text } = scanner.readItemContent({ path: item.path });
782	      const neutral = transformAgent.parse(text, tool, name);
783	      if (firstNeutral == null) firstNeutral = neutral;
784	      tools[tool] = { exists: true, group: assign(agentNeutralKey(neutral)) };
785	    } catch (e) {
786	      tools[tool] = { exists: false, group: null, error: e.message };
787	      errors.push(tool + ': ' + e.message);
788	    }
789	  }
790	  return {
791	    scope,
792	    scopeLabel: scopeLabelFor(scope),
793	    name,
794	    tags: agentTagsFor(name, firstNeutral),
795	    tools,
796	    groups: groupOf.size,
797	    syncState: syncStateOf(tools),
798	    canonicalExists,
799	    canonicalGroup: canonicalExists ? groupOf.get(agentNeutralKey(canonNeutral)) : null,
800	    ...(errors.length ? { error: errors.join(' | ') } : {}),
801	  };
802	}
