804	// (공개) 동기화 매트릭스. kind: 'skill'|'agent'.
805	//  - 시작 시 projectsEnsureScanned()로 자동 발견(레지스트리 비었을 때만 1회 스캔+등록, D27-③).
806	//  - 반환: { kind, autoScan:{scanned,adopted}, rows:[...], counts:{synced,partial,drift,single} }.
807	function syncMatrix({ kind }) {
808	  if (kind !== 'skill' && kind !== 'agent') {
809	    throw new Error("알 수 없는 kind: " + kind + " ('skill'|'agent')");
810	  }
811	  const autoScan = projectsEnsureScanned();
812	  const rows = kind === 'skill' ? skillMatrix() : agentMatrix();
813	  // scope 정렬: 전역 먼저, 그다음 프로젝트 경로순. 같은 scope 내에서는 이름순.
814	  rows.sort((a, b) => {
815	    if (a.scope !== b.scope) {
816	      if (a.scope === 'global') return -1;
817	      if (b.scope === 'global') return 1;
818	      return a.scope < b.scope ? -1 : 1;
819	    }
820	    return a.name < b.name ? -1 : a.name > b.name ? 1 : 0;
821	  });
822	  const counts = { synced: 0, partial: 0, drift: 0, single: 0 };
823	  for (const r of rows) counts[r.syncState] = (counts[r.syncState] || 0) + 1;
824	  return { kind, autoScan, rows, counts };
825	}
