827	// ================= 지시문 매트릭스 / 한 방 동기화 (UX v2 — F2) =================
828	// D27/UX v2: canonical은 순수 백업이라 지시문 비교 계산에 넣지 않는다(3파일만 비교).
829	// 해시·그룹·상태 로직은 syncMatrix(buildSkillRow)의 규칙을 그대로 재사용한다(contentHash + 그룹 번호).
830	// 읽기 실패는 throw하지 않고 해당 모델에 readError로 담아 우아하게 반환한다(D26).
831	
832	// (1) instrMatrix — 전역 지시문 3파일 비교.
833	//  - 모델별 { exists, group(내용 해시 그룹 번호|null), readError? } 반환.
834	//  - 종합 상태(syncState):
835	//      synced : 셋 다 존재 + 같은 해시(그룹 1개)
836	//      drift  : 존재하는 것끼리 해시가 갈림(그룹 2개 이상)
837	//      partial: 일부만 존재(있는 것끼리는 동일)
838	//      none   : 하나도 없음
839	function instrMatrix() {
840	  // 내용 해시 → 그룹 번호(1부터). buildSkillRow와 동일한 idiom.
841	  const groupOf = new Map();
842	  let nextGroup = 0;
843	  const assign = (h) => {
844	    if (!groupOf.has(h)) groupOf.set(h, ++nextGroup);
845	    return groupOf.get(h);
846	  };
847	
848	  const discovered = scanner.discoverInstructions(); // {tool, path, exists, ...}[]
849	  const models = {};
850	  for (const tool of paths.TOOLS) {
851	    const item = discovered.find((i) => i.tool === tool);
852	    if (!item || !item.exists) {
853	      models[tool] = { exists: false, group: null };
854	      continue;
855	    }
856	    try {
857	      // readItemContent는 거부목록/PI 가드를 상속(지시문 본문 읽기는 사용자 트리거 화면 로드).
858	      const { text } = scanner.readItemContent({ path: item.path });
859	      models[tool] = { exists: true, group: assign(contentHash(text)) };
860	    } catch (e) {
861	      // 우아한 실패(D26): 이 모델만 readError, 나머지는 계속.
862	      models[tool] = { exists: false, group: null, readError: e.message };
863	    }
864	  }
865	
866	  // 종합 상태 판정(지시문 전용 — none이 별도 상태라 syncStateOf와 규칙이 다름).
867	  const present = paths.TOOLS.map((t) => models[t]).filter((s) => s.exists && s.group != null);
868	  let syncState;
869	  if (present.length === 0) syncState = 'none';
870	  else if (groupOf.size > 1) syncState = 'drift';
871	  else syncState = present.length === paths.TOOLS.length ? 'synced' : 'partial';
872	
873	  return {
874	    canonId: CANON_ID,
875	    models,
876	    groups: groupOf.size,
877	    syncState,
878	  };
879	}
