881	// (2) instrSync — 기준 모델로 한 방 동기화.
882	//  - base = 'claude'|'codex'|'gemini'.
883	//  - apply:false(기본): 실제 쓰기 없이 모델별 diff 요약(변경 라인 수·생성될 파일 여부)만 반환.
884	//      · 쓰기 없음 검증을 위해 canonical에도 쓰지 않는다 — 기준 파일 본문을 직접 읽어
885	//        transformInstr.render + diff.lineDiff로 대상별 미리보기를 만든다(디스크 무변경).
886	//  - apply:true: 기존 pull({from:base}) → push({to,apply:true}) 파이프라인을 그대로 재사용
887	//      (자동 백업·synclog·PI 게이트·gitCommit 상속). 새 쓰기 경로는 만들지 않는다.
888	//      PI 게이트는 pull이 PiGateError를 던지며 여기서 잡지 않고 그대로 전파(서버 409).
889	function instrSync({ base, apply, piAck }) {
890	  if (!paths.TOOLS.includes(base)) {
891	    throw new Error("기준 모델(base)이 올바르지 않습니다: " + base + " ('claude'|'codex'|'gemini')");
892	  }
893	  const baseItem = scanner.discoverInstructions().find((i) => i.tool === base);
894	  if (!baseItem || !baseItem.exists) {
895	    throw new Error(`기준 모델(${base})의 지시문 파일이 없습니다: ${baseItem ? baseItem.path : base}`);
896	  }
897	
898	  if (!apply) {
899	    // 미리보기: 디스크 무변경. 기준 파일 본문을 읽어 대상 모델별 diff 요약만 만든다.
900	    const { text: baseBody } = scanner.readItemContent({ path: baseItem.path });
901	    const targets = paths.TOOLS.filter((t) => t !== base).map((to) => {
902	      const rendered = transformInstr.render(baseBody, to); // 지시문은 본문 변환 없음(파일명만)
903	      const exists = fs.existsSync(rendered.targetPath);
904	      const deployed = exists ? fs.readFileSync(rendered.targetPath, 'utf8') : '';
905	      const d = diff.lineDiff(deployed, rendered.body);
906	      const added = d.filter((x) => x.type === '+').length;
907	      const removed = d.filter((x) => x.type === '-').length;
908	      return {
909	        to,
910	        targetPath: rendered.targetPath,
911	        exists,
912	        willCreate: !exists,     // 대상 파일이 없으면 새로 생성됨
913	        hasChanges: diff.hasChanges(d),
914	        added,                   // 추가될 라인 수
915	        removed,                 // 사라질 라인 수
916	        changedLines: added + removed,
917	      };
918	    });
919	    return { applied: false, base, targets };
920	  }
921	
922	  // 적용: 기존 파이프라인 재사용. pull(base→canonical) 후 나머지 모델로 push(apply:true).
923	  const pulled = pull({ from: base, piAck }); // PI 게이트 시 PiGateError 전파
924	  if (!pulled.imported) {
925	    // PI 게이트에서 사용자가 제외를 선택 → 기준을 canonical에 넣지 않아 동기화 중단.
926	    return { applied: true, base, pulled: { imported: false, reason: pulled.reason }, results: [] };
927	  }
928	  const results = [];
929	  for (const to of paths.TOOLS) {
930	    if (to === base) continue;
931	    try {
932	      const r = push({ to, apply: true }); // 자동 백업·synclog·gitCommit 상속
933	      results.push({ to, applied: true, targetPath: r.targetPath, backupPath: r.backupPath || null });
934	    } catch (e) {
935	      // 부분 실패: 중단하지 말고 모델별 결과로 기록.
936	      results.push({ to, applied: false, error: e.message });
937	    }
938	  }
939	  return {
940	    applied: true,
941	    base,
942	    pulled: { imported: true, source_tool: pulled.meta.source_tool, piHandled: pulled.piHandled },
943	    results,
944	  };
945	}
