1721	async function loadUsage() {

1	'use strict';
2	// 트랙 B — agent 변환. 중립 스키마 ↔ 세 도구 포맷.
3	//  - Claude/Gemini: .md + YAML frontmatter, 본문 = system_prompt   (gray-matter)
4	//  - Codex:        .toml, developer_instructions = system_prompt   (@iarna/toml)
5	//  - tools: Claude↔Gemini만 이름 매핑(확인된 것만). 미확인/Codex는 "손실(⚠)"로 표시.
6	//
7	// 중립 스키마(JSON):
8	//   { id, name, description, system_prompt, model, tools:[Claude이름...], source_tool, source_notes }
9	
10	const matter = require('gray-matter');
11	const TOML = require('@iarna/toml');
12	const toolMap = require('./tool-map');
13	
14	// ---------- 중립 스키마 → 각 도구 포맷 (render) ----------
15	function render(neutral, tool) {
16	  const losses = [];
17	  if (tool === 'claude') {
18	    const fm = clean({ name: neutral.name, description: neutral.description, model: neutral.model, tools: neutral.tools });
19	    return { tool, ext: '.md', content: matter.stringify('\n' + (neutral.system_prompt || ''), fm), losses };
20	  }
21	  if (tool === 'gemini') {
22	    const mapped = [];
23	    for (const t of neutral.tools || []) {
24	      const g = toolMap.claudeToGemini(t);
25	      if (g) mapped.push(g);
26	      else losses.push(`tools: '${t}' → Gemini 매핑 미확인(제외)`);
27	    }
28	    const fm = clean({ name: neutral.name, description: neutral.description, model: neutral.model, tools: mapped });
29	    return { tool, ext: '.md', content: matter.stringify('\n' + (neutral.system_prompt || ''), fm), losses };
30	  }
31	  if (tool === 'codex') {
32	    // Codex는 에이전트별 tools 필드가 없음 → tools 전부 손실
33	    for (const t of neutral.tools || []) losses.push(`tools: '${t}' → Codex 미지원(에이전트별 tools 없음)`);
34	    const obj = clean({
35	      name: neutral.name,
36	      description: neutral.description,
37	      model: neutral.model,
38	      developer_instructions: neutral.system_prompt || '',
39	    });
40	    return { tool, ext: '.toml', content: TOML.stringify(obj), losses };
41	  }
42	  throw new Error('알 수 없는 도구: ' + tool);
43	}
44	
45	// ---------- 각 도구 포맷 → 중립 스키마 (parse, pull용) ----------
46	function parse(content, tool, name) {
47	  if (tool === 'claude') {
48	    const { data, content: body } = matter(content);
49	    return base(name, data, body.trim(), data.tools || [], 'claude');
50	  }
51	  if (tool === 'gemini') {
52	    const { data, content: body } = matter(content);
53	    const claudeTools = [];
54	    const notes = [];
55	    for (const g of data.tools || []) {
56	      const c = toolMap.geminiToClaude(g);
57	      if (c) claudeTools.push(c);
58	      else notes.push(`Gemini 도구 '${g}' → Claude 매핑 미확인`);
59	    }
60	    const n = base(name, data, body.trim(), claudeTools, 'gemini');
61	    if (notes.length) n.source_notes = notes.join('; ');
62	    return n;
63	  }
64	  if (tool === 'codex') {
65	    const data = TOML.parse(content);
66	    // Codex는 tools가 없음 → 중립 tools는 빈 배열
67	    const n = base(name, data, (data.developer_instructions || '').trim(), [], 'codex');
68	    return n;
69	  }
70	  throw new Error('알 수 없는 도구: ' + tool);
71	}
72	
73	// ---------- 보조 ----------
74	function base(name, data, systemPrompt, tools, sourceTool) {
75	  return {
76	    id: 'agent-' + (data.name || name),
77	    name: data.name || name,
78	    description: data.description || '',
79	    system_prompt: systemPrompt,
80	    model: data.model || null,
81	    tools,
82	    source_tool: sourceTool,
83	  };
84	}
85	
86	// undefined/null/빈배열 필드는 빼서 출력이 깔끔하도록
87	function clean(obj) {
88	  const out = {};
89	  for (const [k, v] of Object.entries(obj)) {
90	    if (v === undefined || v === null) continue;
91	    if (Array.isArray(v) && v.length === 0) continue;
92	    out[k] = v;
93	  }
94	  return out;
95	}
96	
97	module.exports = { render, parse };
